proof fn phi_2_mod_add_self_aligned(a: nat, c: nat)
    requires
        aligned(a, c),
        c > 0,
    ensures
        aligned(a + c, c),
{
    mod_add_zero(a, c, c);
}

proof fn phi_3_aligned_sum_commutes(a: nat, b: nat, c: nat)
    requires
        aligned(a, c),
        aligned(b, c),
        c > 0,
    ensures
        aligned(a + b, c) && aligned(b + a, c),
{
    mod_add_zero(a, b, c);
    mod_add_zero(b, a, c);
}

proof fn phi_4_aligned_double(a: nat, c: nat)
    requires
        aligned(a, c),
        c > 0,
    ensures
        aligned(a + a, c),
{
    mod_add_zero(a, a, c);
}
